#!/bin/bash
set -e
cd ~/chaos_tester
echo "=== Deploy v8: Real Perplexity queries, condensed tables, improved parser ==="
echo "Decoding ai_visibility.py..." && echo "" | base64 -d > modules/ai_visibility.py
echo "Decoding report.html..." && echo "" | base64 -d > templates/report.html
echo "Decoding dashboard.html..." && echo "" | base64 -d > templates/dashboard.html
echo "Decoding app.py..." && echo "" | base64 -d > app.py

echo ""
python3 -c "
import ast
for f in ['modules/ai_visibility.py', 'app.py']:
    ast.parse(open(f).read())
    print(f'  {f}: OK')
"

echo ""
echo "Committing..."
git add -A
git commit -m "feat: real Perplexity AI queries, condensed tables, revenue-based competitor filtering

- Query Perplexity sonar API for real AI search results (key via env var)
- Fall back to simulation when no API key is set
- Improved parser handles bold name format and citation brackets
- Revenue bucket logic filters competitors to similar revenue range (internal only)
- Condense Detailed Results table to first 5 rows with expand/scroll
- Condense AI Results table to first 5 rows with expand/scroll
- Remove API key field from dashboard (read from env var only)
- Debug logging for API key detection and query flow"

echo ""
echo "Pushing to GitHub..."
git push origin main

echo ""
echo "Deploying to Cloud Run..."
gcloud run deploy chaos-tester \
  --project chaos-tester \
  --source . \
  --region us-central1 \
  --allow-unauthenticated \
  --quiet

echo ""
echo "=== v8 Deploy Complete ==="
echo ""
echo "IMPORTANT: Now set the API key as an env var (run this separately):"
echo "  gcloud run services update chaos-tester --project chaos-tester --region us-central1 --set-env-vars PERPLEXITY_API_KEY=your-key-here --quiet"
